package com.example.mpos.report;
import android.database.Cursor;import android.os.Bundle;import android.widget.TextView;import androidx.appcompat.app.AppCompatActivity;import com.example.mpos.R;import com.example.mpos.database.DatabaseHelper;import com.example.mpos.utils.CurrencyUtils;
public class ReportActivity extends AppCompatActivity{public void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_report);DatabaseHelper db=new DatabaseHelper(this);Cursor c=db.getReadableDatabase().rawQuery("SELECT COUNT(*),COALESCE(SUM(total_amount),0) FROM orders WHERE status='PAID'",null);String text="Tổng quan doanh thu\n";try{if(c.moveToFirst())text+="\nĐơn đã thanh toán: "+c.getInt(0)+"\nDoanh thu: "+CurrencyUtils.vnd(c.getLong(1));}finally{c.close();}Cursor top=db.getReadableDatabase().rawQuery("SELECT product_name,SUM(quantity) q FROM order_items GROUP BY product_id ORDER BY q DESC LIMIT 3",null);try{if(top.moveToFirst()){text+="\n\nSản phẩm bán chạy";do{text+="\n• "+top.getString(0)+" — "+top.getInt(1)+" sản phẩm";}while(top.moveToNext());}}finally{top.close();}((TextView)findViewById(R.id.txtReport)).setText(text);findViewById(R.id.btnBack).setOnClickListener(v->finish());}}
